import boto3

def lambda_handler(event, context):
    s3 = boto3.client('s3')
    dynamodb = boto3.resource('dynamodb')
    sns_client = boto3.client('sns')
    sqs = boto3.client('sqs')

    # Example S3 operation
    response = s3.list_buckets()
    print("List of buckets:", response['Buckets'])

    # Example DynamoDB operation
    table = dynamodb.Table('example_table')
    response = table.scan()
    print("DynamoDB items:", response['Items'])

    # Example SNS operation
    topic_arn = 'arn:aws:sns:us-east-1:123456789012:example_topic'
    sns_client.publish(TopicArn=topic_arn, Message='Hello from Lambda!')

    # Example SQS operation
    queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/example_queue'
    response = sqs.receive_message(QueueUrl=queue_url)
    print("SQS message:", response.get('Messages', []))

    return {
        'statusCode': 200,
        'body': 'Lambda function executed successfully!'
    }